<script setup lang="ts">
definePageMeta({layout:'admin',middleware:'admin-auth'});useSeoMeta({title:'Dashboard Admin',robots:'noindex, nofollow'});const{account}=useAdminAccount();const now=ref(new Date());let timer:ReturnType<typeof setInterval>;onMounted(()=>timer=setInterval(()=>now.value=new Date(),1000));onBeforeUnmount(()=>clearInterval(timer));const wibTime=computed(()=>new Intl.DateTimeFormat('id-ID',{timeZone:'Asia/Jakarta',hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false}).format(now.value));const wibDate=computed(()=>new Intl.DateTimeFormat('id-ID',{timeZone:'Asia/Jakarta',weekday:'long',day:'numeric',month:'long',year:'numeric'}).format(now.value));const hour=computed(()=>Number(new Intl.DateTimeFormat('en-US',{timeZone:'Asia/Jakarta',hour:'2-digit',hour12:false}).format(now.value)));const greeting=computed(()=>hour.value<11?'Selamat pagi':hour.value<15?'Selamat siang':hour.value<18?'Selamat sore':'Selamat malam');const menus=[{label:'Beranda',to:'/admin/halaman/beranda',icon:'mdi:home-edit-outline',tone:'bg-blue-50 text-blue-700'},{label:'Profil',to:'/admin/profil',icon:'mdi:school-outline',tone:'bg-violet-50 text-violet-700'},{label:'Akademik',to:'/admin/akademik',icon:'mdi:file-pdf-box',tone:'bg-red-50 text-red-700'},{label:'Kesiswaan',to:'/admin/kesiswaan',icon:'mdi:account-group-outline',tone:'bg-emerald-50 text-emerald-700'},{label:'Informasi',to:'/admin/informasi',icon:'mdi:newspaper-variant-outline',tone:'bg-amber-50 text-amber-700'},{label:'Galeri',to:'/admin/galeri',icon:'mdi:image-multiple-outline',tone:'bg-pink-50 text-pink-700'},{label:'Kontak',to:'/admin/kontak',icon:'mdi:map-marker-outline',tone:'bg-cyan-50 text-cyan-700'},{label:'PPDB',to:'/admin/ppdb',icon:'mdi:account-school-outline',tone:'bg-indigo-50 text-indigo-700'}]
</script>
<template><div><section class="relative overflow-hidden rounded-3xl bg-school-navy p-7 text-white md:p-10"><div class="absolute -right-16 -top-20 size-64 rounded-full bg-school-blue/30"></div><div class="relative flex flex-wrap items-end justify-between gap-6"><div><p class="text-blue-200">{{greeting}},</p><h1 class="mt-2 text-3xl font-bold md:text-4xl">{{account.name}} 👋</h1><p class="mt-3 max-w-xl text-blue-100">Siap membuat informasi sekolah hari ini lebih menarik dan selalu terbaru?</p></div><div class="rounded-2xl border border-white/15 bg-white/10 px-6 py-4 text-right backdrop-blur"><p class="font-mono text-3xl font-bold tracking-wider">{{wibTime}}</p><p class="mt-1 text-xs text-blue-100">{{wibDate}} · WIB</p></div></div></section><div class="mt-8 flex items-center justify-between"><div><h2 class="text-xl font-bold text-school-navy">Menu Cepat</h2><p class="text-sm text-muted">Pilih bagian yang ingin dikelola.</p></div></div><div class="mt-5 grid gap-4 grid-cols-2 lg:grid-cols-4"><NuxtLink v-for="menu in menus" :key="menu.to" :to="menu.to" class="card group p-5 transition hover:-translate-y-1 hover:shadow-lg"><span class="grid size-12 place-items-center rounded-2xl" :class="menu.tone"><Icon :name="menu.icon" size="26"/></span><b class="mt-4 block text-school-navy">{{menu.label}}</b><span class="mt-2 inline-flex items-center gap-1 text-xs font-semibold text-school-action">Kelola <Icon name="mdi:arrow-right" class="transition group-hover:translate-x-1"/></span></NuxtLink></div></div></template>
